function collectText(resp) {
  if (typeof resp.output_text === 'string' && resp.output_text.trim()) {
    return resp.output_text.trim();
  }
  const texts = [];
  for (const item of resp.output || []) {
    for (const part of item.content || []) {
      if (typeof part.text === 'string' && part.text.trim()) {
        texts.push(part.text.trim());
      }
    }
  }
  return texts.join('\n\n').trim();
}
const response = $json || {};
const promptCtx = ($items('Build Supervisor Prompt', 0, 0) || [])[0]?.json || {};
const markdown = collectText(response);
if (!markdown) {
  throw new Error('Empty supervisor response');
}
const priorityMatch = markdown.match(/##?\s*PRIORITY[\s\S]*?(LOW|MEDIUM|HIGH|CRITICAL)/i);
const goMatch = markdown.match(/##?\s*GO\s*\/\s*NO-GO[\s\S]*?\b(GO|NO-GO)\b/i);
const ownerMatch = markdown.match(/##?\s*RECOMMENDED OWNER[\s\S]*?\b(Human|Codex|Observe)\b/i);
const lines = markdown.split(/\r?\n/).map(x => x.trim()).filter(Boolean);
const highlights = lines.filter(line => !line.startsWith('#')).slice(0, 3);
const timestamp = new Date().toISOString();
const finalReport = `# Current Supervisor Status\n\n- Generated at: ${timestamp}\n- Trigger source: ${promptCtx.trigger_source || 'unknown'}\n- Model: ${promptCtx.model || 'unknown'}\n- Report path: docs/audits/CURRENT_SUPERVISOR_STATUS.md\n\n${markdown.trim()}\n`;
return [{ json: { trigger_source: promptCtx.trigger_source || 'unknown', model: promptCtx.model || 'unknown', markdown, final_report: finalReport, report_b64_url: encodeURIComponent(Buffer.from(finalReport, 'utf8').toString('base64')), priority: priorityMatch ? priorityMatch[1].toUpperCase() : 'UNKNOWN', go_no_go: goMatch ? goMatch[1].toUpperCase() : 'UNKNOWN', recommended_owner: ownerMatch ? ownerMatch[1] : 'Unknown', highlights, report_path: 'docs/audits/CURRENT_SUPERVISOR_STATUS.md' } }];

const parsed = ($items('Parse Supervisor Response', 0, 0) || [])[0]?.json || {};
const writeResult = $json || {};
const highlights = Array.isArray(parsed.highlights) ? parsed.highlights.slice(0, 3) : [];
const bulletItems = highlights.map(line => `<li>${line.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</li>`).join('');
const generatedAt = new Date().toISOString();
const subject = `AEB Supervisor ${parsed.priority || 'UNKNOWN'} ${generatedAt.slice(0, 10)}`;
const html = [
  `<h2>AEB Supervisor</h2>`,
  `<p><strong>Priority:</strong> ${parsed.priority || 'UNKNOWN'} | <strong>${parsed.go_no_go || 'UNKNOWN'}</strong></p>`,
  `<p><strong>Owner:</strong> ${parsed.recommended_owner || 'Unknown'}</p>`,
  bulletItems ? `<ul>${bulletItems}</ul>` : '',
  `<p><strong>Report:</strong> ${parsed.report_path || 'docs/audits/CURRENT_SUPERVISOR_STATUS.md'}</p>`,
  `<p><strong>Write:</strong> ${writeResult.ok ? 'OK' : 'FAIL'}</p>`,
  `<hr>`,
  `<pre>${(parsed.markdown || '').replace(/</g, '&lt;').replace(/>/g, '&gt;')}</pre>`
].filter(Boolean).join('');
return [{ json: { subject, html } }];
